def from_base(X):
    base = "0123456789`~!@#$%^&*()-=_+[]{};:'|,./<>?qwertyuiopasdfghjklzxcvbnmQWERTYUIOPASDFGHJKLZXCVBNM";
    l = len(base)
    r = 0
    e = 1
    for c in X:
        r += base.index(c)*e
        e *= l
    return r

def solve():
    N, mod = RL()
    print(from_base(A[N]) % mod)


    

T = 1
for t in range(T):
    solve()
